  using (workspace_id in (select id from public.workspaces where owner_user_id = (select auth.uid())));

create policy "owners can delete creative agent assets"
  on public.creative_agent_assets for delete
  using (workspace_id in (select id from public.workspaces where owner_user_id = (select auth.uid())));

drop policy if exists "owners can read creative agent issues" on public.creative_agent_review_issues;
drop policy if exists "owners can insert creative agent issues" on public.creative_agent_review_issues;
drop policy if exists "owners can update creative agent issues" on public.creative_agent_review_issues;
drop policy if exists "owners can delete creative agent issues" on public.creative_agent_review_issues;

create policy "owners can read creative agent issues"
  on public.creative_agent_review_issues for select
  using (workspace_id in (select id from public.workspaces where owner_user_id = (select auth.uid())));

create policy "owners can insert creative agent issues"
  on public.creative_agent_review_issues for insert
  with check (workspace_id in (select id from public.workspaces where owner_user_id = (select auth.uid())));

create policy "owners can update creative agent issues"
